static void uhf_draw_right_text(Canvas* canvas, int y, const char* text) {
    if(!canvas || !text) return;

    const int width = canvas_string_width(canvas, text);
    int x = 128 - width;
    if(x < 0) x = 0;
    canvas_draw_str(canvas, x, y, text);
}

static void uhf_draw_scan_state_icon(Canvas* canvas, int x, int y, bool running) {
    if(!canvas) return;

    if(running) {
        // Pause icon
        canvas_draw_box(canvas, x, y, 2, 7);
        canvas_draw_box(canvas, x + 4, y, 2, 7);
    } else {
        // Play icon
        canvas_draw_line(canvas, x, y, x, y + 6);
        canvas_draw_line(canvas, x, y, x + 5, y + 3);
        canvas_draw_line(canvas, x, y + 6, x + 5, y + 3);
    }
}

static void uhf_draw_scan_hint(Canvas* canvas, bool running) {
    if(!canvas) return;

    canvas_set_font(canvas, FontSecondary);
    const char* ok_text = "OK";
    const char* action_text = "Scan";
    const int ok_width = canvas_string_width(canvas, ok_text);
    const int action_width = canvas_string_width(canvas, action_text);
    const int icon_width = 6;
    const int gap_before_icon = 3;
    const int gap_after_icon = 4;
    const int total_width = ok_width + gap_before_icon + icon_width + gap_after_icon + action_width;

    int start_x = (128 - total_width) / 2;
    if(start_x < 0) start_x = 0;

    canvas_draw_str(canvas, start_x, 63, ok_text);

    const int icon_x = start_x + ok_width + gap_before_icon;
    const int icon_y = 56;
    uhf_draw_scan_state_icon(canvas, icon_x, icon_y, running);
    canvas_draw_str(canvas, icon_x + icon_width + gap_after_icon, 63, action_text);
}

